//! Death #2 — Amplituhedron attention V2 (LearnedMix variant).
//!
//! Companion to [`crate::scattering_attention`] (V1, `CatQK` row composition,
//! proven softmax-incompatible by `Gnosis.AmplituhedronAntisymmetryNoGo`).
//! V2 generalizes the KPlane row construction to a learned 2×2 mixing block:
//!
//! ```text
//!   row_a(i, j) = α · q_i^k + β · k_j^k
//!   row_b(i, j) = γ · q_i^k + δ · k_j^k
//! ```
//!
//! At the identity block `⟨1, 0, 0, 1⟩` this collapses exactly to V1's
//! `[q; k]` rows (parity test below pins this byte-identical). Asymmetric
//! blocks (NOT `α = β ∧ γ = δ`) are the only ones that can structurally
//! escape the antisymmetry no-go — see the Lean spec
//! `open-source/gnosis-math/Gnosis/AmplituhedronAttentionV2Architecture.lean`,
//! `learned_mix_invariant`.
//!
//! ## Status
//!
//! **Phase A — library only.** No wasm-bindgen exports, no binaries, no
//! `model.rs::forward_range_chunk` wiring. Phase B (training) and Phase C
//! (perplexity eval) come later. The point of Phase A is to land the
//! kernel + parity tests so subsequent phases have a stable substrate.
//!
//! ## Quantization
//!
//! Inherits the V1 contract: `f32 → i64` via `round(x * QUANT_SCALE)` with
//! `QUANT_SCALE = 1024.0`. The mixing happens in `f32` BEFORE quantization
//! so that at the identity block the i64 rows are bit-identical to V1's
//! `quantize_row(q_sub)` / `quantize_row(k_sub)`. (Doing the mix in i64
//! after quantization would risk an off-by-one rounding drift in the
//! identity case — observed in scratch implementation, fixed by mixing
//! first.)
//!
//! ## What this is NOT
//!
//! Same exclusions as V1: no multi-head wrapper, no positional embedding,
//! no causal mask, no KV-cache integration. Single-head, single-layer,
//! whole-sequence at once. Caller slices Q/K/V per-head.

#![allow(dead_code)]

use crate::scattering_amplitude::{scattering_amplitude, KPlane};

// ════════════════════════════════════════════════════════════════════
// QUANTIZATION CONSTANTS (mirror scattering_attention.rs)
// ════════════════════════════════════════════════════════════════════

/// f32 → i64 fixed-point scale. Must match
/// `scattering_attention::QUANT_SCALE` so the identity-mix parity test
/// holds bit-exactly.
const QUANT_SCALE: f32 = 1024.0;

/// `SCALE^2` — divisor for 2×2-minor amplitudes. Each Plücker coordinate
/// of a 2-plane is a 2×2 determinant, scaling as `SCALE^2`.
const QUANT_SCALE_SQ: f32 = QUANT_SCALE * QUANT_SCALE;

/// Quantize an f32 row to i64 by `round(x * SCALE)`. Identical to the
/// V1 helper of the same name — duplicated rather than re-exported to
/// keep V1's module surface unchanged (Phase A scope rule: don't touch
/// `scattering_attention.rs`).
#[inline]
fn quantize_row(row: &[f32]) -> Vec<i64> {
    row.iter()
        .map(|&v| (v * QUANT_SCALE).round() as i64)
        .collect()
}

// ════════════════════════════════════════════════════════════════════
// SOFTMAX HELPER (mirror scattering_attention.rs)
// ════════════════════════════════════════════════════════════════════

/// Numerically stable softmax over a row. Subtracts max before exp.
/// Duplicated from V1 for the same module-isolation reason as
/// `quantize_row` above.
fn softmax_inplace(row: &mut [f32]) {
    if row.is_empty() {
        return;
    }
    let max = row.iter().cloned().fold(f32::NEG_INFINITY, f32::max);
    let mut sum = 0.0_f32;
    for v in row.iter_mut() {
        *v = (*v - max).exp();
        sum += *v;
    }
    if sum > 0.0 {
        let inv = 1.0 / sum;
        for v in row.iter_mut() {
            *v *= inv;
        }
    }
}

// ════════════════════════════════════════════════════════════════════
// MIXING BLOCK (mirrors Lean MixingBlock from
// AmplituhedronAttentionV2Architecture.lean)
// ════════════════════════════════════════════════════════════════════

/// 2×2 mixing block `[[α, β], [γ, δ]]` driving the LearnedMix row
/// composition:
///
/// ```text
///   row_a(i, j) = α · q_i + β · k_j
///   row_b(i, j) = γ · q_i + δ · k_j
/// ```
///
/// Mirrors Lean
/// `AmplituhedronAttentionV2Architecture.MixingBlock` (Int → f32 here;
/// the Lean side stays on `Int` for the algebraic theorems, the Rust
/// side uses f32 because the mix happens pre-quantization on real
/// hidden states).
#[derive(Debug, Clone, Copy)]
pub struct MixingBlock {
    pub alpha: f32,
    pub beta: f32,
    pub gamma: f32,
    pub delta: f32,
}

impl MixingBlock {
    /// Identity block — KPlane rows reduce to V1's `[q; k]` composition
    /// exactly. Any V2 caller that wants V1 semantics must use this and
    /// MUST observe the byte-identical parity asserted by
    /// `tests::v2_identity_mix_matches_v1_at_identity`.
    pub const IDENTITY: Self = MixingBlock {
        alpha: 1.0,
        beta: 0.0,
        gamma: 0.0,
        delta: 1.0,
    };

    /// Lean `learned_mix_invariant.asymmetricInQK`:
    /// `NOT (α = β AND γ = δ)`. A block that fails this is q-k-symmetric;
    /// its rows are scalar multiples of `q + k`, the KPlane has rank ≤ 1,
    /// and the antisymmetry no-go (`Gnosis.AmplituhedronAntisymmetryNoGo`)
    /// reapplies verbatim. Such blocks MUST NOT be used to seed a
    /// LearnedMix training run — they are provably wasted compute.
    ///
    /// f32 equality is used deliberately (not approximate compare): the
    /// invariant is a *structural* condition on the block itself, not a
    /// numerical condition on the resulting amplitude. A block initialized
    /// with `α = β = 1.0` exactly is structurally symmetric; a block with
    /// `α = 1.0, β = 1.0 + 1e-9` is structurally asymmetric (even though
    /// the resulting amplitude will be numerically close to the symmetric
    /// case until training pulls them apart).
    pub fn is_asymmetric_in_qk(&self) -> bool {
        self.alpha != self.beta || self.gamma != self.delta
    }
}

// ════════════════════════════════════════════════════════════════════
// V2 ATTENTION (LearnedMix variant)
// ════════════════════════════════════════════════════════════════════

/// Drop-in alternative to
/// [`crate::scattering_attention::attention_via_amplituhedron`] with a
/// learned 2×2 mixing block on the KPlane rows.
///
/// Math:
///
/// ```text
///   For each (i, j):
///     row_a^k = α · q_i^k + β · k_j^k     (length k_subspace)
///     row_b^k = γ · q_i^k + δ · k_j^k
///     plane   = KPlane{rows = [row_a^k, row_b^k], k = 2, d = k_subspace}
///     amp(i, j) = Σ_S dual[S] · det(plane.cols(S))   for S ∈ kSubsets(2, k_sub)
///   logits(i, ·) = amp(i, ·) / (SCALE^2 · sqrt(k_sub))
///   weights(i, ·) = softmax(logits(i, ·))
///   out(i)      = Σ_j weights(i, j) · v_j
/// ```
///
/// Inputs:
///   * `q`, `k`, `v` — row-major `[seq_len, d_head]`.
///   * `standing_wave_dims` — index set in `[0..d_head)` defining the
///     k-subspace. Same role as in V1.
///   * `mix` — 2×2 mixing block. `MixingBlock::IDENTITY` recovers V1.
///   * `dual` — covector of length `C(k_subspace, 2)` paired with the
///     Plücker coords. In V1 this was hardcoded `vec![1; n_minors]`;
///     V2 surfaces it as a parameter so the Phase B trainer can learn it.
///
/// Returns: `[seq_len, d_head]`.
///
/// Edge cases match V1: empty seq → empty Vec; `k_subspace.len() < 2`
/// → uniform-weighted V mix (same fallback as
/// `scattering_attention::attention_via_amplituhedron`).
///
/// Panics on shape mismatch in `q`/`k`/`v` (programming error). Does
/// NOT panic on `dual.len() != n_minors`; trailing entries on either
/// side are ignored (same `List.zip` truncation semantics as Lean's
/// `scatteringAmplitude` / V1's wrapping).
pub fn attention_via_amplituhedron_v2(
    q: &[f32],
    k: &[f32],
    v: &[f32],
    seq_len: usize,
    d_head: usize,
    standing_wave_dims: &[usize],
    mix: MixingBlock,
    dual: &[i64],
) -> Vec<f32> {
    assert_eq!(q.len(), seq_len * d_head, "q shape mismatch");
    assert_eq!(k.len(), seq_len * d_head, "k shape mismatch");
    assert_eq!(v.len(), seq_len * d_head, "v shape mismatch");

    if seq_len == 0 {
        return Vec::new();
    }

    let mut out = vec![0.0_f32; seq_len * d_head];

    // Standing-wave-dim sanity. Same silent-clamp + uniform-fallback
    // semantics as V1 — see comments there for why we don't panic.
    let swd: Vec<usize> = standing_wave_dims
        .iter()
        .copied()
        .filter(|&d| d < d_head)
        .collect();
    if swd.len() < 2 {
        let w = 1.0 / (seq_len as f32);
        for i in 0..seq_len {
            for j in 0..seq_len {
                let v_row = &v[j * d_head..(j + 1) * d_head];
                let out_row = &mut out[i * d_head..(i + 1) * d_head];
                for d in 0..d_head {
                    out_row[d] += w * v_row[d];
                }
            }
        }
        return out;
    }
    let k_sub = swd.len();

    // Pre-extract the f32 standing-wave projections of Q and K. We do
    // NOT pre-quantize: the mixing has to happen on f32 BEFORE
    // quantization so the identity-block path is bit-identical to V1's
    // `quantize_row(q_sub)` / `quantize_row(k_sub)` results.
    let mut q_sub: Vec<Vec<f32>> = Vec::with_capacity(seq_len);
    let mut k_sub_proj: Vec<Vec<f32>> = Vec::with_capacity(seq_len);
    for i in 0..seq_len {
        let q_row = &q[i * d_head..(i + 1) * d_head];
        let k_row = &k[i * d_head..(i + 1) * d_head];
        q_sub.push(swd.iter().map(|&d| q_row[d]).collect());
        k_sub_proj.push(swd.iter().map(|&d| k_row[d]).collect());
    }

    let amp_rescale = (1.0 / QUANT_SCALE_SQ) * (1.0 / (k_sub as f32).sqrt());

    let mut logits = vec![0.0_f32; seq_len];
    let mut row_a = vec![0.0_f32; k_sub];
    let mut row_b = vec![0.0_f32; k_sub];

    for i in 0..seq_len {
        let q_i = &q_sub[i];
        for j in 0..seq_len {
            let k_j = &k_sub_proj[j];

            // Mixed rows in f32 — identity block (α=1, β=0, γ=0, δ=1)
            // makes `row_a = q_i` and `row_b = k_j` byte-identical to
            // V1's projection (single multiply by 1.0 + add of 0.0
            // returns the original f32 bit pattern under IEEE 754).
            for d in 0..k_sub {
                row_a[d] = mix.alpha * q_i[d] + mix.beta * k_j[d];
                row_b[d] = mix.gamma * q_i[d] + mix.delta * k_j[d];
            }

            let row_a_q = quantize_row(&row_a);
            let row_b_q = quantize_row(&row_b);

            let plane = KPlane::new(2, k_sub, vec![row_a_q, row_b_q])
                .expect("scattering_attention_v2: KPlane shape invariant violated");
            let amp_i64 = scattering_amplitude(&plane, dual);
            // Cast through f64 to preserve precision before the divide.
            logits[j] = (amp_i64 as f64) as f32 * amp_rescale;
        }
        softmax_inplace(&mut logits);
        for j in 0..seq_len {
            let w = logits[j];
            let v_row = &v[j * d_head..(j + 1) * d_head];
            let out_row = &mut out[i * d_head..(i + 1) * d_head];
            for d in 0..d_head {
                out_row[d] += w * v_row[d];
            }
        }
    }
    out
}

// ════════════════════════════════════════════════════════════════════
// PARITY + INVARIANT TESTS
// ════════════════════════════════════════════════════════════════════

#[cfg(test)]
mod tests {
    use super::*;
    use crate::scattering_attention::attention_via_amplituhedron;

    /// Deterministic SplitMix64-style synth, matching the V1 test helper.
    /// Reproducible across machines; no dev-deps RNG.
    fn synth(seed: u64, idx: usize) -> f32 {
        let mut z = seed.wrapping_add((idx as u64).wrapping_mul(0x9E37_79B9_7F4A_7C15));
        z = (z ^ (z >> 30)).wrapping_mul(0xBF58_476D_1CE4_E5B9);
        z = (z ^ (z >> 27)).wrapping_mul(0x94D0_49BB_1331_11EB);
        z ^= z >> 31;
        let u = ((z >> 40) as f32) / ((1u32 << 24) as f32);
        2.0 * u - 1.0
    }

    /// Build the all-ones dual covector of length `C(k_sub, 2)`,
    /// matching V1's hardcoded dual choice. For the parity test this is
    /// non-negotiable: V1 has no dual parameter and uses `vec![1; n]`.
    fn all_ones_dual(k_sub: usize) -> Vec<i64> {
        let n = k_sub * (k_sub - 1) / 2;
        vec![1_i64; n]
    }

    // ── TEST 1: identity block parity with V1 ─────────────────────────

    /// Identity mixing block (`α=1, β=0, γ=0, δ=1`) must reduce the V2
    /// pipeline to V1 byte-identically. This is the core contract: V2 is
    /// a strict generalization of V1, not a re-derivation.
    ///
    /// The byte comparison is via `f32::to_bits` — even a single ULP
    /// drift would indicate a floating-point reordering between the V1
    /// path (direct quantize of projection) and the V2 path
    /// (`1.0 * x + 0.0 * y` then quantize). Under IEEE 754 these MUST
    /// agree because `1.0 * x = x` exactly and `x + 0.0 = x` exactly
    /// (assuming x is not -0.0; we don't generate -0.0 from `synth`).
    #[test]
    fn v2_identity_mix_matches_v1_at_identity() {
        let seq_len = 4;
        let d_head = 8;
        let q: Vec<f32> = (0..seq_len * d_head).map(|i| synth(0xA1, i)).collect();
        let k: Vec<f32> = (0..seq_len * d_head).map(|i| synth(0xA2, i)).collect();
        let v: Vec<f32> = (0..seq_len * d_head).map(|i| synth(0xA3, i)).collect();
        let swd = vec![0_usize, 2, 5];

        let out_v1 = attention_via_amplituhedron(&q, &k, &v, seq_len, d_head, &swd);
        let dual = all_ones_dual(swd.len());
        let out_v2 = attention_via_amplituhedron_v2(
            &q,
            &k,
            &v,
            seq_len,
            d_head,
            &swd,
            MixingBlock::IDENTITY,
            &dual,
        );

        assert_eq!(out_v1.len(), out_v2.len(), "shape parity");
        for (idx, (a, b)) in out_v1.iter().zip(out_v2.iter()).enumerate() {
            assert_eq!(
                a.to_bits(),
                b.to_bits(),
                "identity-mix bit drift at index {idx}: v1={a} v2={b} \
                 (bits {:#010x} vs {:#010x})",
                a.to_bits(),
                b.to_bits()
            );
        }
    }

    // ── TEST 2: off-diagonal symmetric mix MUST diverge from V1 ──────

    /// Symmetric block `α=β=γ=δ=0.5` makes both rows equal to
    /// `0.5 (q + k)`. The KPlane then has rank ≤ 1, every 2×2 minor is
    /// 0, and every amplitude is 0 → uniform softmax weights → output
    /// is the average of V rows. V1 produces non-uniform attention, so
    /// the two MUST differ.
    ///
    /// Beyond proving the mixing actually changes the math, this is the
    /// concrete numerical witness for the Lean spec's
    /// `symmetric_block_violates_invariant` theorem: a symmetric block
    /// degenerates the polytope and gives the average-V "no-information"
    /// output — the same effective behaviour as the
    /// `learned_mix_invariant` failure case.
    #[test]
    fn v2_off_diagonal_mix_diverges_from_v1() {
        let seq_len = 4;
        let d_head = 8;
        let q: Vec<f32> = (0..seq_len * d_head).map(|i| synth(0xB1, i)).collect();
        let k: Vec<f32> = (0..seq_len * d_head).map(|i| synth(0xB2, i)).collect();
        let v: Vec<f32> = (0..seq_len * d_head).map(|i| synth(0xB3, i)).collect();
        let swd = vec![0_usize, 2, 5];

        let out_v1 = attention_via_amplituhedron(&q, &k, &v, seq_len, d_head, &swd);
        let dual = all_ones_dual(swd.len());
        let symmetric_mix = MixingBlock {
            alpha: 0.5,
            beta: 0.5,
            gamma: 0.5,
            delta: 0.5,
        };
        // Sanity: this block is exactly the kind that fails the Lean
        // invariant. If the asymmetry check ever returns true here,
        // either f32 equality semantics broke or the implementation was
        // flipped — either way the divergence claim below would be
        // testing the wrong thing.
        assert!(
            !symmetric_mix.is_asymmetric_in_qk(),
            "test setup: 0.5-block is supposed to be q-k-symmetric"
        );
        let out_v2 =
            attention_via_amplituhedron_v2(&q, &k, &v, seq_len, d_head, &swd, symmetric_mix, &dual);

        let mut max_abs_diff = 0.0_f32;
        for (a, b) in out_v1.iter().zip(out_v2.iter()) {
            let d = (a - b).abs();
            if d > max_abs_diff {
                max_abs_diff = d;
            }
        }
        assert!(
            max_abs_diff > 1e-6,
            "symmetric mix MUST diverge from V1; got max-abs-diff={max_abs_diff} (≤ 1e-6)"
        );
    }

    // ── TEST 3: finiteness across several mix blocks ─────────────────

    #[test]
    fn v2_preserves_finiteness() {
        let seq_len = 4;
        let d_head = 8;
        let q: Vec<f32> = (0..seq_len * d_head).map(|i| synth(0xC1, i)).collect();
        let k: Vec<f32> = (0..seq_len * d_head).map(|i| synth(0xC2, i)).collect();
        let v: Vec<f32> = (0..seq_len * d_head).map(|i| synth(0xC3, i)).collect();
        let swd = vec![0_usize, 1, 3]; // k_sub = 3
        let dual = all_ones_dual(swd.len());

        let mixes = vec![
            MixingBlock::IDENTITY,
            MixingBlock {
                alpha: 1.0,
                beta: 0.5,
                gamma: -0.25,
                delta: 1.0,
            },
            MixingBlock {
                alpha: 2.0,
                beta: -1.0,
                gamma: 0.7,
                delta: 0.3,
            },
            MixingBlock {
                alpha: 0.0,
                beta: 1.0,
                gamma: 1.0,
                delta: 0.0,
            }, // pure swap
        ];

        for (mix_idx, mix) in mixes.iter().enumerate() {
            let out =
                attention_via_amplituhedron_v2(&q, &k, &v, seq_len, d_head, &swd, *mix, &dual);
            assert_eq!(out.len(), seq_len * d_head, "shape on mix {mix_idx}");
            for (i, x) in out.iter().enumerate() {
                assert!(
                    x.is_finite(),
                    "non-finite output at mix={mix_idx} index={i}: {x} \
                     (mix={mix:?})"
                );
            }
        }
    }

    // ── TEST 4: Lean `learned_mix_invariant` decision agreement ──────

    /// Pin the decision table for the Lean `learned_mix_invariant`
    /// (a.k.a. `MixingBlock.asymmetricInQK`):
    ///
    /// ```text
    ///   asymmetricInQK m  ↔  m.α ≠ m.β ∨ m.γ ≠ m.δ
    /// ```
    ///
    /// If a future refactor swaps the OR for an AND, this test catches
    /// it before any LearnedMix sweep wastes compute on a provably
    /// degenerate seed.
    #[test]
    fn mixing_block_is_asymmetric_correctly() {
        // Identity: α≠β (1≠0) AND γ≠δ (0≠1) → asymmetric.
        assert!(
            MixingBlock::IDENTITY.is_asymmetric_in_qk(),
            "identity block MUST be asymmetric (matches Lean \
             identity_block_is_asymmetric)"
        );

        // Pure-symmetric: α=β AND γ=δ → NOT asymmetric. This is the
        // exact concrete witness type from the Lean theorem
        // `symmetric_block_violates_invariant`.
        let symmetric = MixingBlock {
            alpha: 1.0,
            beta: 1.0,
            gamma: 2.0,
            delta: 2.0,
        };
        assert!(
            !symmetric.is_asymmetric_in_qk(),
            "symmetric block (α=β ∧ γ=δ) MUST fail asymmetry"
        );

        // Mixed: α=β but γ≠δ → asymmetric (the OR fires on the second
        // disjunct). Catches a future bug where someone flips OR→AND.
        let half_asym = MixingBlock {
            alpha: 1.0,
            beta: 1.0,
            gamma: 0.0,
            delta: 1.0,
        };
        assert!(
            half_asym.is_asymmetric_in_qk(),
            "α=β ∧ γ≠δ MUST be asymmetric (Lean Or.inr branch)"
        );

        // Belt-and-suspenders: α≠β but γ=δ → asymmetric (OR fires on
        // the first disjunct). Symmetric to the half_asym case above.
        let half_asym_other = MixingBlock {
            alpha: 1.0,
            beta: 0.0,
            gamma: 3.0,
            delta: 3.0,
        };
        assert!(
            half_asym_other.is_asymmetric_in_qk(),
            "α≠β ∧ γ=δ MUST be asymmetric (Lean Or.inl branch)"
        );
    }

    // ── TEST 5: hand-computed Lean-oracle amplitude on one (i, j) ────

    /// Construct a deterministic configuration where the V2 amplitude
    /// for one (i, j) pair can be hand-computed via the Lean math, then
    /// recover it from the implementation by inspecting the
    /// pre-softmax logit.
    ///
    /// Configuration (chosen so quantization is exact — every f32 value
    /// is an integer multiple of 1/SCALE = 1/1024):
    ///
    /// ```text
    ///   d_head = 4
    ///   seq_len = 1                  (single (i, j) = (0, 0) pair)
    ///   standing_wave_dims = [0, 1, 2]  (k_sub = 3)
    ///   q[0] = [1.0, 2.0, 3.0, 99.0]   (last dim ignored; not in swd)
    ///   k[0] = [4.0, 5.0, 6.0, 99.0]
    ///   mix  = MixingBlock { α=1, β=0, γ=2, δ=1 }   (asymmetric)
    ///   dual = [1, 0, 0]              (only the [1,2]-minor contributes)
    /// ```
    ///
    /// Hand math:
    ///   q_sub = [1, 2, 3]
    ///   k_sub = [4, 5, 6]
    ///   row_a = 1·q_sub + 0·k_sub = [1, 2, 3]
    ///   row_b = 2·q_sub + 1·k_sub = [6, 9, 12]
    ///
    ///   Quantize at SCALE=1024:
    ///     row_a_q = [1024, 2048, 3072]
    ///     row_b_q = [6144, 9216, 12288]
    ///
    ///   kSubsets(2, 3) = [[1,2], [0,2], [0,1]]   (reverse-lex)
    ///   Plücker on [1,2]: det [[2048, 3072], [9216, 12288]]
    ///                   = 2048·12288 − 3072·9216
    ///                   = 25_165_824 − 28_311_552
    ///                   = -3_145_728
    ///   Plücker on [0,2]: det [[1024, 3072], [6144, 12288]]
    ///                   = 1024·12288 − 3072·6144
    ///                   = 12_582_912 − 18_874_368
    ///                   = -6_291_456
    ///   Plücker on [0,1]: det [[1024, 2048], [6144, 9216]]
    ///                   = 1024·9216 − 2048·6144
    ///                   = 9_437_184 − 12_582_912
    ///                   = -3_145_728
    ///
    ///   amp_i64 = ⟨[-3145728, -6291456, -3145728], [1, 0, 0]⟩
    ///           = -3_145_728
    ///
    ///   amp_rescale = 1 / (1024² · √3)
    ///   logit       = -3_145_728 / (1_048_576 · √3)
    ///               = -3 / √3
    ///               = -√3
    ///               ≈ -1.7320508
    ///
    /// Single-key softmax → weight 1.0 → out = v[0]. Unique key, so
    /// the softmax output is independent of the logit value. To verify
    /// the *logit* (which is where the Lean math lives), we use a
    /// two-key configuration with a known second amplitude.
    ///
    /// Approach: use seq_len=2, set k[1] = k[0] and v rows distinct,
    /// then BOTH logits equal -√3 → uniform softmax weights → output
    /// row = average of v[0] and v[1]. The fact that the output equals
    /// the average is the byte-level witness that BOTH amplitudes
    /// computed to exactly -3_145_728 and rescaled to exactly -√3.
    #[test]
    fn v2_with_known_dual_matches_lean_oracle() {
        let seq_len = 2;
        let d_head = 4;
        let q: Vec<f32> = vec![
            // q[0]
            1.0, 2.0, 3.0, 99.0, // q[1] same as q[0] so both queries see the same logits
            1.0, 2.0, 3.0, 99.0,
        ];
        let k: Vec<f32> = vec![
            // k[0]
            4.0, 5.0, 6.0, 99.0,
            // k[1] same as k[0] → both keys give identical amplitude
            4.0, 5.0, 6.0, 99.0,
        ];
        let v: Vec<f32> = vec![
            // v[0]
            10.0, 20.0, 30.0, 40.0, // v[1]
            70.0, 80.0, 90.0, 100.0,
        ];
        let swd = vec![0_usize, 1, 2]; // k_sub = 3
        let mix = MixingBlock {
            alpha: 1.0,
            beta: 0.0,
            gamma: 2.0,
            delta: 1.0,
        };
        // Cite the Lean invariant explicitly: this block must be asymmetric
        // (otherwise we'd be computing the trivial-amplitude-zero case).
        assert!(
            mix.is_asymmetric_in_qk(),
            "test mix must satisfy learned_mix_invariant"
        );

        // Dual: single nonzero on the [1, 2] minor (the FIRST entry of
        // kSubsets(2, 3)). This isolates one Plücker coordinate so the
        // hand math is one determinant, not a sum.
        let dual = vec![1_i64, 0, 0];

        let out = attention_via_amplituhedron_v2(&q, &k, &v, seq_len, d_head, &swd, mix, &dual);

        // With identical (q, k) for both keys, both amplitudes are equal
        // → softmax weights are uniform 0.5 each → each output row is
        // the mean of v[0] and v[1].
        let v0 = &v[0..d_head];
        let v1 = &v[d_head..2 * d_head];
        let expected: Vec<f32> = v0
            .iter()
            .zip(v1.iter())
            .map(|(a, b)| 0.5 * (a + b))
            .collect();

        for query in 0..seq_len {
            let row = &out[query * d_head..(query + 1) * d_head];
            for d in 0..d_head {
                let got = row[d];
                let want = expected[d];
                // Strict tolerance: the only f32 ops involved are
                // softmax of two equal logits (→ exactly 0.5) and a
                // single multiply-add. Drift should be sub-ULP for
                // well-conditioned values like these.
                assert!(
                    (got - want).abs() < 1e-5,
                    "query={query} d={d}: got {got} want {want} \
                     (single-minor Lean-oracle amplitude check failed)"
                );
            }
        }

        // Now verify the SIGN and MAGNITUDE of the per-(i, j) amplitude
        // by re-running the kernel computation directly on the same
        // mixed rows and asserting the exact i64 the Lean math predicts.
        // This is the strict witness — if the implementation ever
        // reorders the determinant or flips a sign, this fires.
        let q_sub: Vec<f32> = swd.iter().map(|&d| q[d]).collect();
        let k_sub_proj: Vec<f32> = swd.iter().map(|&d| k[d]).collect();
        let row_a: Vec<f32> = q_sub
            .iter()
            .zip(k_sub_proj.iter())
            .map(|(qi, kj)| mix.alpha * qi + mix.beta * kj)
            .collect();
        let row_b: Vec<f32> = q_sub
            .iter()
            .zip(k_sub_proj.iter())
            .map(|(qi, kj)| mix.gamma * qi + mix.delta * kj)
            .collect();
        let row_a_q = quantize_row(&row_a);
        let row_b_q = quantize_row(&row_b);
        // Hand-computed quantized rows from the test docstring above.
        assert_eq!(
            row_a_q,
            vec![1024, 2048, 3072],
            "row_a quantization mismatch — Lean oracle path broken"
        );
        assert_eq!(
            row_b_q,
            vec![6144, 9216, 12288],
            "row_b quantization mismatch — Lean oracle path broken"
        );
        let plane = KPlane::new(2, swd.len(), vec![row_a_q, row_b_q]).expect("valid 2-plane");
        let amp = scattering_amplitude(&plane, &dual);
        assert_eq!(
            amp, -3_145_728,
            "single-minor amplitude must equal Lean hand-computed \
             value −3,145,728"
        );
    }
}
